 namespace WPAICG\Vector\Providers\Qdrant\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Qdrant_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function normalize_filter_payload_keys_logic(array $filter): array { if (isset($filter['key']) && is_string($filter['key'])) { if (str_starts_with($filter['key'], 'payload.')) { $filter['key'] = substr($filter['key'], 8); } if (is_keyword_payload_field_logic($filter['key']) && isset($filter['match']) && is_array($filter['match'])) { if (array_key_exists('value', $filter['match']) && is_scalar($filter['match']['value'])) { $filter['match']['value'] = (string) $filter['match']['value']; } if (isset($filter['match']['any']) && is_array($filter['match']['any'])) { $filter['match']['any'] = array_map(static function ($value): string { return is_scalar($value) ? (string) $value : ''; }, $filter['match']['any']); $filter['match']['any'] = array_values(array_filter($filter['match']['any'], static function (string $value): bool { return $value !== ''; })); } } } foreach ($filter as $key => $value) { if (is_array($value)) { $filter[$key] = normalize_filter_payload_keys_logic($value); } } return $filter; } function ensure_payload_indexes_for_filter_logic(AIPKit_Vector_Qdrant_Strategy $strategyInstance, string $collection_name, array $filter): bool|WP_Error { $conditions = extract_payload_filter_conditions_logic($filter); if (empty($conditions)) { return true; } static $known_indexed_fields = []; $collection_cache_key = $collection_name; if (!isset($known_indexed_fields[$collection_cache_key])) { $known_indexed_fields[$collection_cache_key] = []; if (function_exists(__NAMESPACE__ . '\\describe_index_logic')) { $description = describe_index_logic($strategyInstance, $collection_name); if (!is_wp_error($description)) { $payload_schema = $description['payload_schema'] ?? []; if (is_array($payload_schema)) { $known_indexed_fields[$collection_cache_key] = array_fill_keys(array_keys($payload_schema), true); } } } } foreach ($con